import { AxiosRequestConfig } from 'axios';

import CryptoJS from 'crypto-js';
import md5 from 'md5';
import { getVersion, compareVersion, gerNonce } from '@/utils';
import { isEdstars } from '../utils/url';

// get headers from JSBridge
// return promise
export async function getAppHeaders(axiosConfig: AxiosRequestConfig) {
  const header: Record<string, any> = {
    appKey: 'parent_v1.9.0',
    bu: 2,
    clientId: isEdstars() ? 551203 : 551202,
    deviceId: '',
    familyId: '',
    nonce: gerNonce(),
    platform:
      navigator.userAgent.indexOf('Android') > -1 ||
      navigator.userAgent.indexOf('Adr') > -1
        ? 'Android'
        : 'IOS',
    sn: '',
    stuId: '',
    timeStamp: Math.floor(Date.now() / 1000),
    version: '1.9.0',
    device_code: '',
    busBu: ''
  };
  const nonNeedAddDynamicsHeaderUaList = ['MicroMessenger'];
  const nonNeedAddDynamicsHeaderUaReg = new RegExp(
    nonNeedAddDynamicsHeaderUaList.join('|'),
    'ig'
  );
  const ua = window.navigator.userAgent;
  // 微信邀请直接使用默认header
  if (nonNeedAddDynamicsHeaderUaReg.test(ua)) {
    return normalizeHeader(header, axiosConfig);
  }

  const curVers = await getVersion();
  console.log('curVersion', curVers);

  function getDynamicsHeader() {
    // 仅在1.18版本之后的版本获取动态header
    return new Promise((resolve) => {
      if (compareVersion(curVers.version, '1.18') >= 0) {
        window.ConnectWebViewBridgeSDK.getHeader(
          (data: Record<string, string>) => {
            resolve(data);
          }
        );
      } else {
        return resolve({});
      }
    });
  }

  function getStaticHeader() {
    return new Promise((resolve) => {
      if (compareVersion(curVers.version, '1.16.0') >= 0) {
        window.ConnectWebViewBridgeSDK.getUserInfo(
          (data: Record<string, string>) => {
            header.bu = data.deviceBu || '';
            header.deviceId = data.deviceId || '';
            header.familyId = data.familyId || '';
            header.sn = data.deviceSn || '';
            header.stuId = data.stu_talid || '';
            header.version = curVers.version || '';
            header.device_code = data.device_code || '';
            header.busBu = data.bus_bu || '';

            resolve(normalizeHeader(header, axiosConfig));
          }
        );
      } else {
        resolve(normalizeHeader(header, axiosConfig));
      }
    });
  }

  return Promise.all([getStaticHeader(), getDynamicsHeader()]).then((res) => {
    return Object.assign({}, ...res);
  });
}

const normalizeHeader = (header: any, axiosConfig: AxiosRequestConfig) => {
  const secret = '750230b1ce7f5de1';
  // 需要进行验签的字段
  const sign = md5(
    [
      'appKey',
      'bu',
      'clientId',
      'deviceId',
      'familyId',
      'nonce',
      'platform',
      'sn',
      'stuId',
      'timeStamp',
      'version'
    ]
      .sort()
      .reduce((acc, cur) => acc + header[cur], '') + secret
  );

  return {
    'X-Tal-AppKey': header.appKey,
    'X-Tal-Bu': header.bu,
    'X-Tal-ClientId': header.clientId,
    'X-Tal-DeviceId': header.deviceId,
    'X-Tal-FamilyId':
      (axiosConfig.headers && axiosConfig.headers['X-Tal-FamilyId']) ||
      header.familyId,
    'X-Tal-Nonce': header.nonce,
    'X-Tal-Platform': header.platform,
    'X-Tal-Sn': header.sn,
    'X-Tal-StuId': header.stuId,
    'X-Tal-Timestamp': header.timeStamp,
    'X-Tal-Version': header.version,
    'X-Tal-Sign': sign,
    'X-Tal-DeviceCode': header.device_code,
    'X-Tal-BusBu':
      (axiosConfig.headers && axiosConfig.headers['X-Tal-BusBu']) ||
      header.busBu
  };
};

function getSecretKey() {
  return '16691e0e3d38505501492d8e7599a554';
}

export async function aesEncryptData(sourceStr: any) {
  const secretKey = getSecretKey();
  const key = CryptoJS.enc.Utf8.parse(secretKey);
  const iv = CryptoJS.enc.Utf8.parse(secretKey.slice(0, 16));

  return CryptoJS.AES.encrypt(sourceStr, key, {
    mode: CryptoJS.mode.CBC,
    padding: CryptoJS.pad.Pkcs7,
    iv
  }).toString();
}

export async function aesDecryptData(sourceStr: any) {
  const secretKey = getSecretKey();
  const key = CryptoJS.enc.Utf8.parse(secretKey);
  const iv = CryptoJS.enc.Utf8.parse(secretKey.slice(0, 16));

  return CryptoJS.AES.decrypt(sourceStr, key, {
    mode: CryptoJS.mode.CBC,
    padding: CryptoJS.pad.Pkcs7,
    iv
  }).toString(CryptoJS.enc.Utf8);
}
