/* eslint-disable @typescript-eslint/explicit-module-boundary-types */
import axios, { AxiosRequestConfig, AxiosResponse } from 'axios';
import { getAppHeaders, aesEncryptData, aesDecryptData } from './apiUtils';

export const service = axios.create({
  baseURL: '/',
  timeout: 50000
});

// 请求拦截
service.interceptors.request.use(
  async (config) => {
    // 此处无法统一处理，邀请监督人在微信场景中 错题本导出在服务端
    const axiosConfig = config as any;
    if (config.data && config.data.token) {
      axiosConfig.headers.Authorization = config.data.token;
      delete config.data.token;
    }

    // fix 这个是特殊请求头  且后端未需要这个字段做验签，单独处理
    // 业务中如果传递同名字段, 可能导致body 最后被删掉这个字段
    // if (config.data?.bus_bu) {
    //   axiosConfig.headers['X-Tal-BusBu'] = config.data.bus_bu; // 只有二代机用到
    //   delete config.data.bus_bu;
    // }

    // merge customHeaders into headers
    const customHeaders = await getAppHeaders(config);
    Object.assign(axiosConfig.headers, customHeaders);

    // 请求加密
    if (location.href.indexOf('debug=true') > -1 || process.env.VUE_APP_NODE_ENV == 'development') {
      axiosConfig.url =
        axiosConfig.url +
        (axiosConfig.url.indexOf('?') > -1 ? '&debug=true' : '?debug=true');
    } else {
      if (axiosConfig.data) {
        axiosConfig.data = {
          encrypted_param: await aesEncryptData(
            JSON.stringify(axiosConfig.data)
          ),
          ...axiosConfig.data // 加密稳定之后将会下掉这个
        };
      }
    }

    return axiosConfig;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// 请求拦截
service.interceptors.response.use(
  async (response) => {
    // 只有等于1才需要解密
    if (response.data.data_type === 1) {
      response.data.data = JSON.parse(await aesDecryptData(response.data.data));
    }

    return response;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// 后端api统用返回体
export interface CommonResponseType<T = unknown> {
  data: T;
  errcode: number;
  errmsg: string;
  service_time?: number;
  trace: string;
}

// 定义ResponseType
export type ResponseType<T = null> = Promise<
  AxiosResponse<CommonResponseType<T>>
>;

const ApiService = {
  query(resource: string, config?: AxiosRequestConfig) {
    return service.get(resource, config).catch((error) => {
      throw new Error(`[VUE3-APP] ApiService ${error}`);
    });
  },
  // eslint-disable-next-line @typescript-eslint/ban-types, @typescript-eslint/no-unused-vars, @typescript-eslint/no-explicit-any
  get(resource: string, data: any) {
    const params = {
      params: data
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
    } as any;
    if (data.token) {
      params.headers = { Authorization: data.token };
      delete data.token;
    }

    return service.get(`${resource}`, params).catch((error) => {
      throw new Error(`[VUE3-APP] ApiService ${error}`);
    });
  },

  // axios.get("http://xxx/xxx",{
  //     //参数列表
  //        params:{
  //         id :12345
  //        },
  //     //请求头配置
  //        headers:{
  //          token: token
  //         }
  //     }).then((res)=>{
  //         console.log(res)
  //        })
  //     .catch((error)=>{
  //     console.log(error);
  //     })

  // eslint-disable-next-line @typescript-eslint/explicit-module-boundary-types, @typescript-eslint/ban-types
  post(resource: string, data: object, config?: AxiosRequestConfig) {
    return service.post(`${resource}`, data, config);
    // return service.post(`${resource}?debug=true`, data, config);
  },
  /* eslint-disable*/
  // eslint-disable-next-line @typescript-eslint/ban-types
  update(
    resource: string,
    slug: string,
    data: object,
    config?: AxiosRequestConfig
  ) {
    return service.put(`${resource}/${slug}`, data, config);
  },

  // eslint-disable-next-line @typescript-eslint/ban-types
  put(resource: string, data: object, config?: AxiosRequestConfig) {
    return service.put(`${resource}`, data, config);
  },

  delete(resource: string) {
    return service.delete(resource).catch((error) => {
      throw new Error(`[VUE2-APP] ApiService ${error}`);
    });
  }
};

export default ApiService;
